CREATE SCHEMA IF NOT EXISTS fixture_messy_data_src;
SET search_path TO fixture_messy_data_src;

CREATE TABLE "Account" ( "Id" text PRIMARY KEY, "Name" text, "ERP_Number__c" text, "Customer_Tier__c" text, "Region__c" text, "Industry" text, "Website" text, "BillingCity" text, "BillingCountry" text, "Legacy_Customer_ID__c" text );


CREATE TABLE "Contact" ( "Id" text PRIMARY KEY, "FirstName" text, "LastName" text, "Email" text, "Phone" text, "Title" text, "Role__c" text, "Preferred_Language__c" text, "AccountId" text );


CREATE TABLE "Installed_Asset__c" ( "Id" text PRIMARY KEY, "Name" text, "Serial_Number__c" text, "Warranty_End_Date__c" text, "Account__c" text, "Project__c" text );


CREATE TABLE "Opportunity" ( "Id" text PRIMARY KEY, "Name" text, "StageName" text, "CloseDate" text, "Amount" text, "CurrencyIsoCode" text, "AccountId" text );


CREATE TABLE "Project__c" ( "Id" text PRIMARY KEY, "Name" text, "Project_Status__c" text, "Go_Live_Date__c" text, "Account__c" text, "Opportunity__c" text );

